import type Graphic from "../../Graphic.js";
import type CIMSymbol from "../../symbols/CIMSymbol.js";
import type LineSymbol3D from "../../symbols/LineSymbol3D.js";
import type PictureMarkerSymbol from "../../symbols/PictureMarkerSymbol.js";
import type PointSymbol3D from "../../symbols/PointSymbol3D.js";
import type PolygonSymbol3D from "../../symbols/PolygonSymbol3D.js";
import type SimpleFillSymbol from "../../symbols/SimpleFillSymbol.js";
import type SimpleLineSymbol from "../../symbols/SimpleLineSymbol.js";
import type SimpleMarkerSymbol from "../../symbols/SimpleMarkerSymbol.js";
import type TextSymbol from "../../symbols/TextSymbol.js";
import type WebStyleSymbol from "../../symbols/WebStyleSymbol.js";
import type { Icon } from "@esri/calcite-components/components/calcite-icon";
import type { SymbolUnion } from "../../symbols/types.js";
import type { DrawingMode } from "../../views/draw/types.js";

/** @since 5.0 */
export type State = "disabled" | "ready" | "active";

/** @since 5.0 */
export type SketchCreateEventState = "start" | "active" | "complete" | "cancel";

/** @since 5.0 */
export type SketchUpdateEventState = "start" | "active" | "complete";

/** @since 5.0 */
export type Layout = "vertical" | "horizontal";

/** @since 5.0 */
export type ToolbarKind = "docked" | "floating";

/** @since 5.0 */
export type SketchTool = CreateTool | UpdateTool;

/** @since 5.0 */
export type SelectionTool = "lasso-selection" | "rectangle-selection" | "custom-selection";

/** @since 5.0 */
export type SketchPointSymbol = SimpleMarkerSymbol | PictureMarkerSymbol | PointSymbol3D | TextSymbol | CIMSymbol | WebStyleSymbol;

/** @since 5.0 */
export type SketchPolylineSymbol = SimpleLineSymbol | LineSymbol3D | CIMSymbol;

/** @since 5.0 */
export type SketchPolygonSymbol = SimpleFillSymbol | PolygonSymbol3D | CIMSymbol;

/** @since 5.0 */
export interface UndoEvent {
  /**
   * An array of graphics that are being updated or created.
   *
   * @since 5.0
   */
  graphics: Graphic[];
  /**
   * Name of the create or update tool that is active.
   *
   * @since 5.0
   */
  tool: CreateTool | UpdateTool;
  /**
   * The type of the event.
   *
   * @since 5.0
   */
  type: "undo";
}

/** @since 5.0 */
export interface RedoEvent {
  /**
   * An array of graphics that are being updated or created.
   *
   * @since 5.0
   */
  graphics: Graphic[];
  /**
   * Name of the create or update tool that is active.
   *
   * @since 5.0
   */
  tool: CreateTool | UpdateTool;
  /**
   * The type of the event.
   *
   * @since 5.0
   */
  type: "redo";
}

/** @since 5.0 */
export type CreationMode = "single" | "continuous" | "update";

/**
 * Options used by the create workflow.
 *
 * @since 5.0
 */
export interface CreateOptions {
  /**
   * The default z-value of the newly created geometry. Ignored when `hasZ` is `false` or the layer's elevation mode is set to `absolute-height`.
   *
   * @since 5.0
   */
  defaultZ?: number;
  /**
   * The symbol the newly created graphic should use instead of the default symbol for the specified tool.
   *
   * @since 5.0
   */
  graphicSymbol?: SymbolUnion;
  /**
   * Controls whether the created geometry has z-values or not.
   *
   * @since 5.0
   */
  hasZ?: boolean;
  /**
   * Specifies how the graphic can be created. The create mode applies only when creating
   * `polygon`, `polyline`, `rectangle` and `circle` geometries.
   *
   * Value | Description |
   * ----- | ----------- |
   * hybrid | Vertices are added while the pointer is clicked or dragged. Applies to `polygon` and `polyline`.
   * freehand | Vertices are added while the pointer is dragged. Applies to `polygon`, `polyline` `rectangle` and `circle`. Default for `rectangle` and `circle`.
   * click | Vertices are added when the pointer is clicked. Applies to `polygon`, `polyline` `rectangle` and `circle`. Default for `polygon` and `polyline`.
   *
   * @since 5.0
   */
  mode?: DrawingMode;
  /**
   * Controls whether or not the width and height of the drawn geometry are kept equal. Applies to `rectangle` and `circle`.
   *
   * @since 5.0
   */
  preserveAspectRatio?: boolean;
}

/**
 * Create operation DrawAction tool
 *
 * @since 5.0
 */
export type CreateTool = "point" | "multipoint" | "polyline" | "polygon" | "circle" | "rectangle" | "mesh" | "freehandPolyline" | "freehandPolygon" | "text";

/**
 * This information is returned as `toolEventInfo` parameter for the [Sketch.@create](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#event-create) event when the graphic
 * is being created. It returns [VertexAddEventInfo](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/types/#VertexAddEventInfo)
 * when the user clicks the view or [CursorUpdateEventInfo](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/types/#CursorUpdateEventInfo) or when the user moves the cursor.
 *
 * @since 5.0
 */
export type CreateToolEventInfo = VertexAddEventInfo | VertexRemoveEventInfo | CursorUpdateEventInfo;

/** @since 5.0 */
export interface CreateEvent {
  /**
   * The graphic that is being created.
   *
   * @since 5.0
   */
  graphic?: Graphic | null;
  /**
   * The current state of the event.
   *
   * **Possible Values**
   *
   * Value | Description |
   * ----- | ----------- |
   * start | State changes to `start` when the first vertex is created. Not applicable when creating `points`.
   * active | State is `active` while feature is being created. Not applicable when creating `points`.
   * complete | State changes to `complete` after the [Sketch.complete()](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#complete) method is called, when the user double clicks, presses the `Enter` key or clicks the first vertex of the `polygon` while creating a feature. When `point` is created, the a single `sketch-create` event is fired with the `complete` state.
   * cancel | State changes to `cancel` if the user presses the escape key or the [Sketch.create()](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#create) or [Sketch.cancel()](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#cancel) methods are called during the create operation and before the state changes to `complete`.
   *
   * @since 5.0
   */
  state: SketchCreateEventState;
  /**
   * Name of the create tool.
   *
   * @since 5.0
   */
  tool: CreateTool;
  /**
   * Returns additional information associated with
   * the create operation such as where the user is clicking the view or where the user is moving the cursor to.
   * Value of this parameter changes to `null` when the `create` event's `state` changes to `complete` or `cancel`.
   *
   * @since 5.0
   */
  toolEventInfo?: CreateToolEventInfo | null;
  /**
   * The type of the event.
   *
   * @since 5.0
   */
  type: "create";
}

/** @since 5.0 */
export interface MoveOptions {
  /**
   * Indicates whether more than one selection can be made at once. This applies to the shift+click interaction with the `transform` tool.
   *
   * @default true
   * @since 5.0
   */
  multipleSelectionEnabled?: boolean;
}

/** @since 5.0 */
export interface ReshapeOptions {
  /**
   * Sets the reshape operation on the edge. This affects lines and polygons. Fully supported in 3D, partially in 2D.
   *
   * Value | Description |
   * ----- | ----------- |
   * none | No manipulators show up on the edge. (2D and 3D)
   * split | Manipulators show up to split edges by adding a new vertex. (2D and 3D)
   * offset | Manipulators show up to offset the edges. (only 3D)
   *
   * @default "split"
   * @since 5.0
   */
  edgeOperation?: "none" | "offset" | "split";
  /**
   * Sets the move constraints for the whole shape. Supported in 2D and 3D.
   *
   * Value | Description |
   * ----- | ----------- |
   * none | No move manipulator show up. (2D and 3D)
   * move | Move manipulator show up to move in xy and in z. (2D and 3D)
   * move-xy | Move manipulator show up to move in xy only. (only 3D)
   *
   * @default "move"
   * @since 5.0
   */
  shapeOperation?: "none" | "move" | "move-xy";
  /**
   * Sets the move constraints for the vertex. Only supported in 3D.
   *
   * Value | Description |
   * ----- | ----------- |
   * move | Move manipulator show up to move in xy and in z.
   * move-xy | Move manipulator show up to move in xy only.
   *
   * @default "move"
   * @since 5.0
   */
  vertexOperation?: "move" | "move-xy";
  /**
   * Indicates if the user can create a circular arc from an existing straight-line edge by holding **`Shift`** while dragging a midpoint handle.
   *
   * @default true
   * @since 5.0
   */
  enableCreateCurveFromStraightEdge?: boolean;
}

/** @since 5.0 */
export interface TransformOptions {
  /**
   * Indicates if the `rotation` operation will be enabled when updating graphics. Only applies if `tool` is `transform`.
   *
   * @default true
   * @since 5.0
   */
  enableRotation?: boolean;
  /**
   * Indicates if the `scale` operation will be enabled when updating graphics. Only applies if `tool` is `transform`.
   *
   * @default true
   * @since 5.0
   */
  enableScaling?: boolean;
  /**
   * Indicates if the uniform scale operation will be enabled when updating graphics. `enableScaling`
   * must be set `true` when setting this property to `true`. Only applies if `tool` is `transform` and is always `true` when transforming points that use a [3D object symbol layer](https://developers.arcgis.com/javascript/latest/references/core/symbols/ObjectSymbol3DLayer/).
   *
   * @default false
   * @since 5.0
   */
  preserveAspectRatio?: boolean;
}

/** @since 5.0 */
export interface HighlightOptions {
  /**
   * Indicates if highlighting is enabled for update operations. Only supported in 2D.
   *
   * @default true
   * @since 5.0
   */
  enabled?: boolean;
  /**
   * Indicates the name of the highlight group to use.
   *
   * @default "default"
   * @since 5.0
   */
  name?: string;
}

/** @since 5.0 */
export interface UpdateOptions extends MoveOptions, TransformOptions {
  /**
   * Name of the update tool. Specifies the update operation for the selected graphics. The provided tool will become the [Sketch.activeTool](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#activeTool).
   *
   * **Possible Values**
   *
   * Value | Description |
   * ----- | ----------- |
   * transform | This is the *default* tool for graphics with a [Polygon](https://developers.arcgis.com/javascript/latest/references/core/geometry/Polygon/) geometry, [Polyline](https://developers.arcgis.com/javascript/latest/references/core/geometry/Polyline/) geometry or graphics that use a [3D object symbol layer](https://developers.arcgis.com/javascript/latest/references/core/symbols/ObjectSymbol3DLayer/) with a [Point](https://developers.arcgis.com/javascript/latest/references/core/geometry/Point/) geometry. It allows one or multiple graphics to be scaled, rotated and moved by default. Its default behavior can be changed by setting the `enableRotation`, `enableScaling` or `preserveAspectRatio` arguments when calling the `update` method or setting them on the [Sketch.defaultUpdateOptions](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#defaultUpdateOptions) property when the Sketch widget initializes.
   * reshape | This tool allows the entire graphic or individual vertices of the graphic to be moved. Vertices can be added or removed. This tool can only be used with a single graphic that has a [Polygon](https://developers.arcgis.com/javascript/latest/references/core/geometry/Polygon/) or [Polyline](https://developers.arcgis.com/javascript/latest/references/core/geometry/Polyline/) geometry.
   * move | This is the *default* tool for graphics with a [Point](https://developers.arcgis.com/javascript/latest/references/core/geometry/Point/) geometry that do not use a [3D object symbol layer](https://developers.arcgis.com/javascript/latest/references/core/symbols/ObjectSymbol3DLayer/). It should be used for specific cases where you just want to move selected `polygon` and `polyline` graphics without additional options. Additionally, the `move` tool does not support toggling to different modes, since the `move` operation is built into both the `transform` and `reshape` tools by default.
   *
   * @since 5.0
   */
  tool?: UpdateTool;
  /**
   * Indicates if the graphic being updated can be toggled between `transform` and `reshape` update options.
   *
   * @default true
   * @since 5.0
   */
  toggleToolOnClick?: boolean;
  /**
   * Changes the behavior for the `reshape` tool. Defines the operations for edge and/or the constraints for moving a shape and/or a vertex. Only supported in 3D.
   *
   * @since 5.0
   */
  reshapeOptions?: ReshapeOptions;
  /**
   * Indicates if z-values can be modified when updating the graphic. When enabled, the height handle manipulator is displayed.
   *
   * @default true
   * @since 5.0
   */
  enableZ?: boolean;
  /**
   * Options that control when to display or hide highlights for update operations.
   *
   * @since 5.0
   */
  highlightOptions?: HighlightOptions;
}

/**
 * Update operation component
 *
 * @since 5.0
 */
export type UpdateTool = "move" | "transform" | "reshape";

/**
 * This information is returned as `toolEventInfo` parameter for the [Sketch.@update](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#event-update) event when the user is updating graphics.
 *
 * @since 5.0
 */
export type UpdateToolEventInfo = MoveEventInfo | ReshapeEventInfo | RotateEventInfo | ScaleEventInfo | SelectionChangeEventInfo | VertexAddEventInfo | VertexRemoveEventInfo;

/** @since 5.0 */
export interface UpdateEvent {
  /**
   * An array of graphics that are being updated.
   *
   * @since 5.0
   */
  graphics: Graphic[];
  /**
   * The state of the event.
   *
   * **Possible Values**
   *
   * Value | Description |
   * ----- | ----------- |
   * start | State changes to `start` when a graphic is selected to be updated.
   * active | State is `active` while graphics are being updated and `toolEventInfo` parameter is not `null`.
   * complete | State changes to `complete` after graphics are updated.
   *
   * @since 5.0
   */
  state: SketchUpdateEventState;
  /**
   * Indicates if the update operation was aborted. Set to `true`
   * if the user pressed the escape key, or when the [Sketch.update()](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#update), [Sketch.create()](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#create)
   * or [Sketch.cancel()](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#cancel) method is called before the `update` event's `state` changes to `complete`.
   *
   * @since 5.0
   */
  aborted: boolean;
  /**
   * Name of the update operation tool.
   *
   * @since 5.0
   */
  tool: UpdateTool;
  /**
   * Update operation tool info.
   * Returns additional information associated with the update operation that is taking place for selected graphics
   * and what stage it is at. Value of this parameter changes to `null` when the `update` event's `state` changes to `complete`.
   *
   * @since 5.0
   */
  toolEventInfo?: UpdateToolEventInfo | null;
  /**
   * The type of the event.
   *
   * @since 5.0
   */
  type: "update";
}

/**
 * This information is returned as `toolEventInfo` parameter for the [Sketch.@update](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#event-update)
 * event while the user is moving the graphics. It returns additional information associated with the move operation
 * and what stage it is at.
 *
 * @since 5.0
 * @example
 * // listen to update event
 * sketch.on("update", function(event){
 *   // check if the graphics are done being moved, printout dx, dy parameters to the console.
 *   const eventInfo = event.toolEventInfo;
 *   if (eventInfo && eventInfo.type.includes("move")){
 *     console.log(eventInfo.type, eventInfo.dx, eventInfo.dy);
 *   }
 * });
 */
export interface MoveEventInfo {
  /**
   * Number of pixels moved on the x-axis from the last known position.
   *
   * @since 5.0
   */
  dx: number;
  /**
   * Number of pixels moved on the y-axis from the last known position.
   *
   * @since 5.0
   */
  dy: number;
  /**
   * The instance of the graphic that is being moved.
   *
   * @since 5.0
   */
  mover?: Graphic | null;
  /**
   * Returns information indicating the stage of the move operation.
   *
   * **Possible Values**
   *
   * Value | Description |
   * ----- | ----------- |
   * move-start | The type changes to `move-start` at the start of `move` operation.
   * move | The type changes to `move` while graphics are being moved.
   * move-stop | The type changes to `move-stop` once graphics are moved.
   *
   * @since 5.0
   */
  type: "move-start" | "move" | "move-stop";
}

/**
 * This information is returned as `toolEventInfo` parameter for the [Sketch.@update](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#event-update)
 * event while the user is reshaping the graphics. It returns additional information associated with the reshape operation
 * and what stage it is at.
 *
 * @since 5.0
 * @example
 * // listen to update event
 * sketch.on("update", function(event){
 *   // check if the graphics are done being reshaped, printout updated graphic's geometry and reshape stage.
 *   const eventInfo = event.toolEventInfo;
 *   if (eventInfo && eventInfo.type.includes("reshape")) {
 *     console.log(eventInfo.type, event.graphics[0].geometry);
 *   }
 * });
 */
export interface ReshapeEventInfo {
  /**
   * Returns information indicating the stage of the reshape operation.
   *
   * **Possible Values**
   *
   * Value | Description |
   * ----- | ----------- |
   * reshape-start | The type changes to `reshape-start` at the start of `reshape` operation.
   * reshape | The type changes to `reshape` while graphics are being reshaped.
   * reshape-stop | The type changes to `reshape-stop` once graphics are reshaped.
   *
   * @since 5.0
   */
  type: "reshape-start" | "reshape" | "reshape-stop";
}

/**
 * This information is returned as `toolEventInfo` parameter for the [Sketch.@update](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#event-update)
 * event while the user is rotating the graphics. It returns additional information associated with the rotate operation
 * and what stage it is at.
 *
 * @since 5.0
 * @example
 * // listen to update event
 * sketch.on("update", function(event){
 *   if (event.tool === "transform") {
 *     if (event.toolEventInfo) {
 *       const info = event.toolEventInfo,
 *       type = info.type;
 *
 *       // rotate events only
 *       if (type.includes("rotate")) {
 *         // check if the rotation angle exceeded 45
 *         if (info.angle > 45) {
 *           // complete the graphic update operation
 *           sketch.complete();
 *         }
 *       }
 *     }
 *   }
 * });
 */
export interface RotateEventInfo {
  /**
   * Angle of rotation in degrees.
   *
   * @since 5.0
   */
  angle: number;
  /**
   * Returns information indicating the stage of the rotate operation.
   *
   * **Possible Values**
   *
   * Value | Description |
   * ----- | ----------- |
   * rotate-start | The type changes to `rotate-start` at the start of `rotate` operation.
   * rotate | The type changes to `rotate` while graphics are being rotated.
   * rotate-stop | The type changes to `rotate-stop` once graphics are rotated.
   *
   * @since 5.0
   */
  type: "rotate-start" | "rotate" | "rotate-stop";
}

/**
 * This information is returned as `toolEventInfo` parameter for the [Sketch.@update](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#event-update)
 * event while the user is scaling or resizing the graphics. It returns additional information associated with the scale
 * operation and what stage it is at.
 *
 * @since 5.0
 */
export interface ScaleEventInfo {
  /**
   * Returns information indicating the stage of the scale operation.
   *
   * **Possible Values**
   *
   * Value | Description |
   * ----- | ----------- |
   * scale-start | The type changes to `scale-start` at the start of scale or resize operation.
   * scale | The type changes to `scale` while graphics are being scaled or resized.
   * scale-stop | The type changes to `scale-stop` once graphics are scaled or resized.
   *
   * @since 5.0
   */
  type: "scale-start" | "scale" | "scale-stop";
  /**
   * The x scale factor used to enlarge or shrink the geometry.
   *
   * @since 5.0
   */
  xScale: number;
  /**
   * The y scale factor used to enlarge or shrink the geometry.
   *
   * @since 5.0
   */
  yScale: number;
}

/** @since 5.0 */
export interface VertexInfo {
  /**
   * An array of x,y coordinates representing the vertices added/removed.
   *
   * @since 5.0
   */
  coordinates: number[];
  /**
   * The ring/path index of the added/removed vertex.
   *
   * @since 5.0
   */
  componentIndex: number;
  /**
   * The index of the vertex position.
   *
   * @since 5.0
   */
  vertexIndex: number;
}

/**
 * This information is returned as `toolEventInfo` parameter for the [Sketch.@create](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#event-create)
 * or [Sketch.@update](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#event-update) event when the user adds vertices to the graphic being created or updated.
 *
 * @since 5.0
 * @example
 * // listen to create event
 * sketch.on("create", function(event){
 *   // check if vertices are being added to the graphic that is being updated.
 *   if (event.toolEventInfo && event.toolEventInfo.type === "vertex-add"){
 *     const addedPoint = event.toolEventInfo.added[0].geometry;
 *     console.log(event.toolEventInfo.type, addedPoint.x, addedPoint.y);
 *   }
 * });
 */
export interface VertexAddEventInfo {
  /**
   * An array of x,y coordinates representing the vertices added.
   *
   * @since 5.0
   */
  added: number[] | number[][];
  /**
   * Contains the details of the added vertices to track changes in topology of the geometry.
   *
   * @since 5.0
   */
  vertices: VertexInfo[];
  /** @since 5.0 */
  type: "vertex-add";
}

/**
 * This information is returned as `toolEventInfo` parameter for the [Sketch.@update](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#event-update) event
 * when the user is removing vertices from the graphic.
 *
 * @since 5.0
 * @example
 * // listen to update event
 * sketch.on("update", function(event){
 *   // check if vertices are being added to the graphic that is being updated.
 *   const eventInfo = event.toolEventInfo;
 *   if (eventInfo && eventInfo.type === "vertex-remove"){
 *     const removedPoint = eventInfo.removed[0].geometry;
 *     console.log(eventInfo.type, removedPoint.x,removedPoint.y);
 *   }
 * });
 */
export interface VertexRemoveEventInfo {
  /**
   * An array of x,y coordinates representing the vertices removed.
   *
   * @since 5.0
   */
  removed: number[] | number[][];
  /**
   * Contains the details of the removed vertices to track changes in topology of the geometry.
   *
   * @since 5.0
   */
  vertices: VertexInfo[];
  /** @since 5.0 */
  type: "vertex-remove";
}

/**
 * This information is returned as `toolEventInfo` parameter for the [Sketch.@create](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#event-create)
 * event when the user moves the cursor on the view while the graphic is being created.
 *
 * @since 5.0
 * @example
 * // listen to create event
 * sketch.on("create", function(event){
 *   // respond to create event while the cursor is being moved on the view.
 *   const eventInfo = event.toolEventInfo;
 *   if (eventInfo && eventInfo.type === "cursor-update"){
 *     console.log(eventInfo.type, eventInfo.coordinates[0], eventInfo.coordinates[1]);
 *   }
 * });
 */
export interface CursorUpdateEventInfo {
  /**
   * An array of numbers representing the coordinates of the cursor location.
   *
   * @since 5.0
   */
  coordinates: number[];
  /** @since 5.0 */
  type: "cursor-update";
}

/**
 * This information is returned as `toolEventInfo` parameter for the [Sketch.@update](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/#event-update)
 * event while the user is selecting or deselecting graphics using `Shift+Left-click`.
 *
 * @since 5.0
 * @example
 * // listen to update event
 * sketch.on("update", function(event) {
 *   const eventInfo = event.toolEventInfo;
 *   // check if a graphic is being selected or deselected.
 *   if (eventInfo && eventInfo.type === "selection-change") {
 *     if(eventInfo.added.length > 0) {
 *       // graphic is being added to the currently selected graphics.
 *       console.log("geometry type added: ", eventInfo.added[0].geometry.type);
 *     } else {
 *       // graphic is being removed from the currently selected graphics.
 *       console.log("geometry type removed: ", eventInfo.removed[0].geometry.type);
 *     }
 *   }
 * });
 */
export interface SelectionChangeEventInfo {
  /**
   * An array of [graphics](https://developers.arcgis.com/javascript/latest/references/core/Graphic/) representing the latest graphic selected.
   *
   * @since 5.0
   */
  added: Graphic[];
  /**
   * An array of [graphics](https://developers.arcgis.com/javascript/latest/references/core/Graphic/) representing the latest graphic deselected.
   *
   * @since 5.0
   */
  removed: Graphic[];
  /** @since 5.0 */
  type: "selection-change";
}

/**
 * Detailed information returned within the delete event.
 *
 * @since 5.0
 */
export interface DeleteEvent {
  /**
   * An array of deleted graphics.
   *
   * @since 5.0
   */
  graphics: Graphic[];
  /**
   * Name of the tool that was active when graphics are deleted.
   *
   * @since 5.0
   */
  tool: UpdateTool;
  /**
   * The type of the event.
   *
   * @since 5.0
   */
  type: "delete";
}

/**
 * public
 *
 * @since 5.0
 */
export interface CustomToolOptions {
  /**
   * The string value indicating the [Calcite icon](https://developers.arcgis.com/calcite-design-system/icons/) displayed for the custom tool.
   *
   * @since 5.0
   */
  icon: string;
  /**
   * The text displayed in the tooltip for the custom tool.
   *
   * @since 5.0
   */
  label: string;
  /**
   * The unique identifier string for this custom tool. Value must not overlap with sketch create tool names.
   *
   * @since 5.0
   */
  toolKey: string;
  /**
   * The specific sketch create tool to use for the custom tool.
   *
   * @since 5.0
   */
  toolName: CreateTool;
  /**
   * Specific options for the create tool being used by the custom tool.
   *
   * @since 5.0
   */
  createOptions?: CreateOptions;
}

/** @since 5.0 */
export interface ActionProperties {
  /**
   * Unique ID for the action.
   *
   * @since 5.0
   */
  id: string;
  /**
   * Text label for the action.
   *
   * @since 5.0
   */
  text: string;
  /**
   * Calcite icon string to set for the action.
   *
   * @since 5.0
   * @see [Calcite icon](https://developers.arcgis.com/calcite-design-system/icons/)
   */
  icon: Icon["icon"];
  /**
   * Determines whether the action is enabled or not.
   *
   * @since 5.0
   */
  disabled?: boolean;
  /**
   * Optional callback called when the user clicks on the action.
   *
   * @since 5.0
   */
  onclick?: () => void;
  /**
   * Controls if the action is rendered with an "active" appearance.
   *
   * @since 5.0
   */
  active?: boolean;
  /**
   * Controls if the icon should be flipped when the view is in RTL mode.
   *
   * @since 5.0
   */
  flipRTL?: boolean;
  /**
   * Optional callback called with the HTML element for the action after it is first rendered.
   *
   * @since 5.0
   */
  afterCreate?: (el: HTMLElement) => void;
  /**
   * Optional callback called with the HTML element for the calcite-action after it is removed.
   *
   * @since 5.0
   */
  afterRemoved?: (el: HTMLElement) => void;
  /**
   * Optional callback called with the HTML element for the calcite-action after it is re-rendered with changes.
   *
   * @since 5.0
   */
  afterUpdate?: (el: HTMLElement) => void;
}

/**
 * Defines the configuration for creating custom actions in [Sketch](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/).
 *
 * @since 5.0
 */
export interface CustomActionProperties extends ActionProperties {
  /**
   * Controls the placement of the custom action in [Sketch](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/).
   *
   * @since 5.0
   */
  position: "before-selection-set" | "after-selection-set" | "selection-toolbar" | "settings-before" | "settings-after";
}